CustomField.formula:
ROUND( 8.5 * (
   ( 5 * FLOOR( ( Stage_End__c  - DATETIMEVALUE( '1900-01-08 08:00:00') ) / 7) +
    MIN(5, 
     FLOOR ( MOD ( Stage_End__c  - DATETIMEVALUE( '1900-01-08 08:00:00'), 7) / 1) +
     MIN( 1, 24 / 8.5 * ( MOD( Stage_End__c  - DATETIMEVALUE( '1900-01-08 08:00:00' ), 1 ) ) )
    ) 
   )
 -
   ( 5 * FLOOR( ( Stage_Start__c  - DATETIMEVALUE( '1900-01-08 08:00:00') ) / 7) +
     MIN( 5,
      FLOOR( MOD( Stage_Start__c  - DATETIMEVALUE( '1900-01-08 08:00:00'), 7) / 1) +
      MIN( 1, 24 / 8.5 * ( MOD( Stage_Start__c  - DATETIMEVALUE( '1900-01-08 08:00:00' ), 1) ) )
    )
   ) 
  ), 
2 )
